//
import { ORDINAL_DATATYPE } from '../../../../core/datatype-constants';
import { Registry } from '../../../../core/zc-registry';
import { isArray } from '../../../../utils/zcutils';
import { getSliderShape, getSliderPosition } from '../../../../behaviours/visual-effects/brush-handles/handles';
import { cancelAnimation } from '../../../../utils/animationutils';
import { translateString } from '../../../../utils/svg-transforms';
import { getHoverOptions, getDisabledOptions } from '../../legend-event-helpers';
import { handleShadow } from '../../../../behaviours/visual-effects/brush-handles/handle-shadow';

let BrushD3 = Registry.getComponent('BrushD3');
function HighlightItem(mouse, data) {
    let manager = this,
        { options, chart } = manager,
        { config, dimension, highlightElement, type, markerBound, handles: handleOptions } = options,
        markerConfig = config.slider.marker,
        hoverOptions = getHoverOptions(config),
        filterConfig = getDisabledOptions(config),
        hoverType = hoverOptions.type,
        //
        dt = getHighlightData(data.point, options),
        handles;

    // Show highlight element
    cancelAnimation(highlightElement);
    highlightElement.style('opacity', null);

    if (hoverType === 'inherit') {
        if (filterConfig.type) {
            handles = handlerByType(filterConfig, options, dt);
        } else {
            // TODO: implement hoverOptions.marker
            let { shape: symbolPath, position } = handleOptions;
            handles = getSliderShape(`marker-${markerConfig.shape}`, markerConfig, type, dimension);
            handles.shape = [[symbolPath(markerBound.width(dt), markerBound.height(dt))]];
            handles.style.transform = getTranslate(dt, position(dt), options);
        }
    } else if (hoverType) {
        handles = handlerByType(hoverOptions, options, dt);
    }

    if (handles) {
        BrushD3.ADD_HANDLE(handles, highlightElement);

        let handleElement = highlightElement.selectAll('g.handle--custom');
        if (hoverType === 'inherit') {
            if (filterConfig.type) {
                handleShadow(filterConfig, [handles], handleElement, chart);
            }
        } else if (hoverType) {
            handleShadow(hoverOptions, [handles], handleElement, chart);
        }
    }
}

function handlerByType(handleConfig, options, data) {
    let { dimension, type } = options,
        handlerType = handleConfig.type,
        op = handleConfig[handlerType],
        //
        position = getSliderPosition(type, handlerType, dimension, op.size),
        handles = getSliderShape(handlerType, op, type, dimension),
        updateTransform = style => {
            let transform = style.transform,
                rotateIndex = transform.indexOf('rotate'),
                rotate = rotateIndex > -1 ? ` ${transform.substr(rotateIndex)}` : '',
                xy = options.encode === 'clr' ? getExistingPosition(transform) : position;

            style.transform = getTranslate(data, xy, options) + rotate;
        };

    if (isArray(handles.style)) {
        handles.style.forEach(updateTransform);
    } else {
        updateTransform(handles.style);
    }

    return handles;
}

function getHighlightData(point, options) {
    let { dataType, ranges: userRanges } = options;

    if (dataType === ORDINAL_DATATYPE) {
        return userRanges[point][0];
    } else if (userRanges && userRanges.length) {
        return userRanges[point];
    } else {
        return point.data;
    }
}

function getTranslate(data, markerPosition, options) {
    let { isHorizontal, brushScale } = options,
        bandWidth = brushScale.bandwidth ? brushScale.bandwidth() : 0,
        selection = brushScale(data) + bandWidth / 2,
        pos = [];

    if (isHorizontal) {
        pos[0] = selection;
        pos[1] = markerPosition[1];
    } else {
        pos[0] = markerPosition[0];
        pos[1] = selection;
    }

    return translateString(pos);
}

function getExistingPosition(transform) {
    return transform
        .trim()
        .replace('translate(', '')
        .replace(')', '')
        .split(/[, ]/)
        .map(_ => +_);
}

export { HighlightItem, handlerByType, getHighlightData };
